class Solution:
    def countBinarySubstrings(self, s: str) -> int:
        if not s:
            return 0
        groups = []
        prev = s[0]
        cnt = 1
        for ch in s[1:]:
            if ch == prev:
                cnt += 1
            else:
                groups.append(cnt)
                prev = ch
                cnt = 1
        groups.append(cnt)
        ans = 0
        for i in range(1, len(groups)):
            ans += min(groups[i-1], groups[i])
        return ans

